package gui; import dao.EmployeeDAO; import dao.ProjectDAO; import model.Employee; import model.Project; import model.EmployeeTableModel; import javax.swing.*; import java.awt.*; import java.util.List; 
public class EmployeeForm extends JFrame { String role; int userId; JTable table; EmployeeDAO employeeDAO = new EmployeeDAO(); ProjectDAO projectDAO = new ProjectDAO(); EmployeeTableModel model; public EmployeeForm(String role, int userId) { this.role = role; this.userId = userId; setTitle(role.equals("EMPLOYEE") ? "My Account & Projects" : "Employees"); setExtendedState(JFrame.MAXIMIZED_BOTH); setLayout(new BorderLayout()); JLabel header = new JLabel( role.equals("EMPLOYEE") ? "MY ACCOUNT & PROJECTS" : "EMPLOYEE MANAGEMENT", SwingConstants.CENTER ); header.setFont(new Font("Arial", Font.BOLD, 26)); header.setOpaque(true); header.setBackground(new Color(155, 89, 182)); header.setForeground(Color.WHITE); add(header, BorderLayout.NORTH); JPanel container = new JPanel(); container.setLayout(new BoxLayout(container, BoxLayout.Y_AXIS)); container.setBackground(Color.WHITE); if (role.equals("ADMIN")) { List<Employee> employees = employeeDAO.getAll(); model = new EmployeeTableModel(employees); JTable employeeTable = new JTable(model); container.add(new JLabel("All Employees")); container.add(new JScrollPane(employeeTable)); } else if (role.equals("EMPLOYEE")) { List<Employee> me = (List<Employee>) employeeDAO.getById(userId); List<Project> myProjects = projectDAO.getByEmployee(userId); container.add(new JLabel("My Account")); JTable meTable = new JTable(new EmployeeTableModel(me)); container.add(new JScrollPane(meTable)); container.add(Box.createVerticalStrut(20)); container.add(new JLabel("My Projects")); String[] cols = {"ID", "Title", "Client ID"}; Object[][] data = new Object[myProjects.size()][3]; for (int i = 0; i < myProjects.size(); i++) { Project p = myProjects.get(i); data[i][0] = p.getId(); data[i][1] = p.getTitle(); data[i][2] = p.getClientId(); } JTable projectTable = new JTable(data, cols); container.add(new JScrollPane(projectTable)); } JScrollPane scroll = new JScrollPane(container); add(scroll, BorderLayout.CENTER); setVisible(true); } }
